    }

    const log_level: log.Level = switch (flags.verbose) {
        0 => .info,
        else => .debug,
    };
    log.init(log_level, null, flags.verbose > 0);
    defer log.deinit();

    const socket_path = try resolveSocketPath(alloc, &flags);
    defer alloc.free(socket_path);

